const extIMG = 'data:image/png;base64,'
//const extIMG = '';
const Cast = {
    toNumber: (value) => {
        return Number(value);
    }
};
class AerMusicPlayer {
    static instance;

    constructor(runtime) {
        this.runtime = runtime;
        this.audioElements = {};
        this._formatMessage = runtime.getFormatMessage({
            "zh-cn": {
                "AerMusicPlayer_playmusic": 'ID[id]从 [url] 播放音乐',
                "AerMusicPlayer_resumemusic": 'ID[id]播放音乐',
                "AerMusicPlayer_pausemusic": 'ID[id]暂停音乐',
                "AerMusicPlayer_stopmusic": 'ID[id]停止音乐',
                "AerMusicPlayer_jumptotime": 'ID[id]跳转到时间 [time] 秒',
                "AerMusicPlayer_adjustthevolume": 'ID[id]将音量调到 [volume]',
                "AerMusicPlayer_Ismusicplaying": 'ID[id]是否正在播放音乐?',
                "AerMusicPlayer_Getplaytime": 'ID[id]音乐播放时间（秒）',
                "AerMusicPlayer_Getthetotaldurationofmusic": 'ID[id]音乐总时长（秒）',
                "AerMusicPlayer_GetThreadCount": '获取所有线程的 数量',
                "AerMusicPlayer_GetThreadIdList": '获取所有线程的 ID',
                "AerMusicPlayer_GetThreadUrl": '获取ID [id] 的url',
                "AerMusicPlayer_playAllMusic": '所有线程播放音乐',
                "AerMusicPlayer_pauseAllMusic": '所有线程暂停音乐',
                "AerMusicPlayer_stopAllMusic": '所有线程停止音乐',
                "AerMusicPlayer_changeSpeed": 'ID[id]的音频变速为[speed]',
            },
            en: {
                "AerMusicPlayer_playmusic": 'ID [id] play music from [url]',
                "AerMusicPlayer_resumemusic": 'ID [id] play music',
                "AerMusicPlayer_pausemusic": 'ID [id] pause music ',
                "AerMusicPlayer_stopmusic": 'ID [id] stop the music',
                "AerMusicPlayer_jumptotime": 'ID [id] jump to time [time] (sec)',
                "AerMusicPlayer_adjustthevolume": 'ID [id] Adjust the volume to [volume]',
                "AerMusicPlayer_Ismusicplaying": 'ID [id] Is music playing?',
                "AerMusicPlayer_Getplaytime": 'ID [id] Music playback time (sec)',
                "AerMusicPlayer_Getthetotaldurationofmusic": 'ID [id] Total music duration (sec)',
                "AerMusicPlayer_GetThreadCount": 'Get the number of all threads',
                "AerMusicPlayer_GetThreadIdList": 'Get the IDs of all threads',
                "AerMusicPlayer_GetThreadUrl": 'Get the url of ID [id]',
                "AerMusicPlayer_playAllMusic": 'All threads play music',
                "AerMusicPlayer_pauseAllMusic": 'All threads pause music',
                "AerMusicPlayer_stopAllMusic": 'All threads stop music',
                "AerMusicPlayer_changeSpeed": 'ID[id]change audio speed to[speed]',
            }
        });
        AerMusicPlayer.instance = this;
    }

    formatMessage(id) {
        return this._formatMessage({
            id,
            default: id,
            description: id
        });
    }

    getInfo() {
        return {
            id: 'AerMusicPlayer',
            name: 'AerMini的音乐播放器',
            color1: "#4d4d4f",
            blocks: [
                "---基于 sipc.ink 的 CloudMusic 扩展进行创作",
                {
                    opcode: 'playMusic',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_playmusic"),
                    arguments: {
                        url: { type: "string", defaultValue: 'https://example.com/music.mp3' },
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'resumeMusic',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_resumemusic"),
                    arguments: {
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'pauseMusic',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_pausemusic"),
                    arguments: {
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'stopMusic',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_stopmusic"),
                    arguments: {
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'jumpTotime',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_jumptotime"),
                    arguments: {
                        time: { type: "number", defaultValue: 0 },
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'adjustthevolume',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_adjustthevolume"),
                    arguments: {
                        volume: { type: "number", defaultValue: 100 },
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'Ismusicplaying',
                    blockType: Scratch.BlockType.BOOLEAN,
                    text: this.formatMessage("AerMusicPlayer_Ismusicplaying"),
                    arguments: {
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'Getplaytime',
                    blockType: Scratch.BlockType.REPORTER,
                    text: this.formatMessage("AerMusicPlayer_Getplaytime"),
                    arguments: {
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'Getthetotaldurationofmusic',
                    blockType: Scratch.BlockType.REPORTER,
                    text: this.formatMessage("AerMusicPlayer_Getthetotaldurationofmusic"),
                    arguments: {
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'GetThreadCount',
                    blockType: Scratch.BlockType.REPORTER,
                    text: this.formatMessage("AerMusicPlayer_GetThreadCount")
                },
                {
                    opcode: 'GetThreadIdList',
                    blockType: Scratch.BlockType.REPORTER,
                    text: this.formatMessage("AerMusicPlayer_GetThreadIdList")
                },
                {
                    opcode: 'GetThreadUrl',
                    blockType: Scratch.BlockType.REPORTER,
                    text: this.formatMessage("AerMusicPlayer_GetThreadUrl"),
                    arguments: {
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
                {
                    opcode: 'playAllMusic',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_playAllMusic")
                },
                {
                    opcode: 'pauseAllMusic',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_pauseAllMusic")
                },
                {
                    opcode: 'stopAllMusic',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_stopAllMusic")
                },
                {
                    opcode: 'changeSpeed',
                    blockType: Scratch.BlockType.COMMAND,
                    text: this.formatMessage("AerMusicPlayer_changeSpeed"),
                    arguments: {
                        speed: { type: "number", defaultValue: 1 },
                        id: { type: "string", defaultValue: 'id' }
                    }
                },
            ],
        };
    }

    // 音乐部分
    playMusic(args) {
        const url = args.url;
        const id = args.id;
        if (this.audioElements[id]) {
            this.audioElements[id].pause();
        }
        this.audioElements[id] = new Audio(url);
        this.audioElements[id].addEventListener('canplaythrough', () => {
            this.audioElements[id].play();
        });
        this.audioElements[id].addEventListener('error', (error) => {
        });
        this.audioElements[id].addEventListener('ended', () => {
        });
    }

    // 控制部分
    pauseMusic(args) {
        const id = args.id;
        if (this.audioElements[id]) {
            this.audioElements[id].pause();
        }
    }

    resumeMusic(args) {
        const id = args.id;
        if (this.audioElements[id]) {
            this.audioElements[id].play();
        }
    }

    stopMusic(args) {
        const id = args.id;
        if (this.audioElements[id]) {
            this.audioElements[id].pause();
            delete this.audioElements[id];
            delete this.audioContexts[id];
            delete this.sources[id];
        }
    }

    jumpTotime(args) {
        const time = args.time;
        const id = args.id;
        if (this.audioElements[id]) {
            this.audioElements[id].currentTime = time;
        }
    }

    adjustthevolume(args) {
        const id = args.id;
        if (this.audioElements[id]) {
            const volumePercent = args.volume;
            if (volumePercent >= 0 && volumePercent <= 100) {
                const volume = volumePercent / 100;
                this.audioElements[id].volume = volume;
            }
        }
    }

    playAllMusic() {
        for (const id in this.audioElements) {
            if (this.audioElements.hasOwnProperty(id)) {
                this.audioElements[id].play();
            }
        }
    }

    pauseAllMusic() {
        for (const id in this.audioElements) {
            if (this.audioElements.hasOwnProperty(id)) {
                this.audioElements[id].pause();
            }
        }
    }

    stopAllMusic() {
        for (const id in this.audioElements) {
            if (this.audioElements.hasOwnProperty(id)) {
                this.audioElements[id].pause();
                delete this.audioElements[id];
                delete this.audioContexts[id];
                delete this.sources[id];
            }
        }
    }

    // 信息部分
    Ismusicplaying(args) {
        const id = args.id;
        if (this.audioElements[id]) {
            if (!this.audioElements[id].paused &&!this.audioElements[id].ended) {
                return true;
            } else if (this.audioElements[id].paused) {
                return "pause";
            } else {
                return false;
            }
        } else {
            return false;
        }
    }

    Getplaytime(args) {
        const id = args.id;
        if (this.audioElements[id]) {
            return this.audioElements[id].currentTime;
        }
        return 0;
    }

    Getthetotaldurationofmusic(args) {
        const id = args.id;
        if (this.audioElements[id]) {
            return this.audioElements[id].duration;
        }
        return 0;
    }

    GetThreadCount() {
        return Object.keys(this.audioElements).length;
    }

    GetThreadIdList() {
        return Object.keys(this.audioElements);
    }

    GetThreadUrl(args) {
        const id = args.id;
        if (this.audioElements[id]) {
            return this.audioElements[id].src;
        }
        return '';
    }

    changeSpeed(args) {
        const id = args.id;
        let speed = args.speed;
        if (this.audioElements[id]) {
            if (speed > 0) {
                this.audioElements[id].playbackRate = speed;
            }
        }
    }
}

