window.addEventListener('message', (event) => {
    if (event.data.type === 'getPlayTime') {
        const id = event.data.id;
        const playTime = AerMusicPlayer.instance.Getplaytime({ id });
        event.source.postMessage({ type: 'playTimeResponse', id, time: playTime }, event.origin);
    }
});    